import "./ComingSoonCard.css";
import logo from "../../assets/youmax.png";

function ComingSoonCard() {
    return (
        <div className="container">
            <div className="glass">
                <h1>SEE</h1>
                <img src={logo} alt="logo" />
                <h1>MuM</h1>
            </div>
        </div>
    );
}

export default ComingSoonCard;
